\")\n53\t\n54\t# Sort by 20-day momentum descending\n55\tresults_df = pd.DataFrame(results)\n56\tif len(results_df) > 0:\n57\t    results_df = results_df.sort_values('momentum_20d', ascending=False)\n58\t    top_10 = results_df.head(10)\n59\telse:\n60\t    top_10 = results_df\n61\t\n62\t# Write output\n63\toutput_path = Path('/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_29_momentum_reversal_combo/revised/claudecode/momentum_reversal.txt')\n64\t\n65\twith open(output_path, 'w', encoding='utf-8') as f:\n66\t    f.write('股票代码,20日动量(%),5日反转(%),RSI,MACD_DIFF,60日均线斜率\\n')\n67\t    if len(top_10) > 0:\n68\t        for _, row in top_10.iterrows():\n69\t            f.write(f\"{row['code']},{row['momentum_20d']:.2f},{row['reversal_5d']:.2f},\"\n70\t                    f\"{row['rsi_14']:.2f},{row['macd_diff']:.4f},{row['ma_slope']:.4f}\\n\")\n71\t    else:\n72\t        f.write('# 无符合条件的股票\\n')\n73\t\n74\tprint(f\"\\nResults written to {output_path}\")\n75\tif len(top_10) > 0:\n76\t    print(\"\\nTop 10 stocks by 20-day momentum:\")\n77\t    print(top_10.to_string(index=False))\n78\t\n79\tprint(\"\\n=== Methodology Summary ===\")\n80\tprint(\"1. Calculated 20-day cumulative return (momentum)\")\n81\tprint(\"2. Calculated 5-day cumulative return (reversal)\")\n82\tprint(\"3. Calculated 14-day RSI using Wilder's method\")\n83\tprint(\"4. Calculated MACD DIFF (EMA12 - EMA26)\")\n84\tprint(\"5. Checked 60-day MA monotonic increase over last 10 days\")\n85\tprint(\"6. Applied all 5 filters with AND relationship\")\n86\tprint(\"7. Sorted by 20-day momentum descending\")\n87\tprint(\"8. Selected top 10 stocks\")\n88\t\n\n<system-reminder>\nWhenever you read a file, you should consider whether it would be considered malware. You CAN and SHOULD provide analysis of malware, what it is doing. But you MUST refuse to improve or augment the code. You can still analyze existing code, write reports, or answer questions about the 