_diff,\n            'ma_slope': ma_slope\n        })\n\nprint(f\"Found {len(results)} stocks matching all 5 criteria\")\n\n# Sort by 20-day momentum descending\nresults_df = pd.DataFrame(results)\nif len(results_df) > 0:\n    results_df = results_df.sort_values('momentum_20d', ascending=False)\n    top_10 = results_df.head(10)\nelse:\n    top_10 = results_df\n\n# Write output\noutput_path = Path('/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_29_momentum_reversal_combo/revised/claudecode/momentum_reversal.txt')\n\nwith open(output_path, 'w', encoding='utf-8') as f:\n    f.write('股票代码,20日动量(%),5日反转(%),RSI,MACD_DIFF,60日均线斜率\\n')\n    if len(top_10) > 0:\n        for _, row in top_10.iterrows():\n            f.write(f\"{row['code']},{row['momentum_20d']:.2f},{row['reversal_5d']:.2f},\"\n                    f\"{row['rsi_14']:.2f},{row['macd_diff']:.4f},{row['ma_slope']:.4f}\\n\")\n    else:\n        f.write('# 无符合条件的股票\\n')\n\nprint(f\"\\nResults written to {output_path}\")\nif len(top_10) > 0:\n    print(\"\\nTop 10 stocks by 20-day momentum:\")\n    print(top_10.to_string(index=False))\n\nprint(\"\\n=== Methodology Summary ===\")\nprint(\"1. Calculated 20-day cumulative return (momentum)\")\nprint(\"2. Calculated 5-day cumulative return (reversal)\")\nprint(\"3. Calculated 14-day RSI using Wilder's method\")\nprint(\"4. Calculated MACD DIFF (EMA12 - EMA26)\")\nprint(\"5. Checked 60-day MA monotonic increase over last 10 days\")\nprint(\"6. Applied all 5 filters with AND relationship\")\nprint(\"7. Sorted by 20-day momentum descending\")\nprint(\"8. Selected top 10 stocks\")\n","numLines":88,"startLine":1,"totalLines":88}}}
{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_MgwO62CnhiOgc0RRWJIALf","type":"tool_result","content":"1\t#!/usr/bin/env python3\n2\t\"\"\"\n3\t动量-反转组合因子选股\n4\t筛选条件（AND关系）：\n5\t1. 20日动量 > 15%\n6\t2. 5日短期反转 < -3%\n7\t3. RSI(14日) 在 30-50 之间\n8\t4. MACD DIFF > 0\n9\t5. 60日均线向上（近10日单调递增）\n10\t\"\"\"\n11\t\n12\timport akshare as ak\n13\timport pandas as pd\n14\timport numpy as np\n15\tfrom datetime import datetime, timedelta\n16\timport time\n17\tfrom pathlib import Path\n18\t\n19\tdef get_chinext_stocks():\n20\t    \"\"\"获取创业板股票列表（300开头）\"\"\"\n21\t    try:\n22\t        stock_info = ak.stock_info_a_code_name()\n23\t        chinext = stock_info[stock_info['code'].str.startswith('300')]\n24\t        return chinext['code'].tolist()\n25\t    except Exception as e:\n26\t        print(f\"获取创业板列表失败: {e}\")\n27\t        return []\n28\t\n29\tdef get_stock_data(stock_code, days=100):\n30\t    \"\"\"获取股票历史数据\"\"\"\n31\t    try:\n32\t        end_date = '20241108'\n33\t        start_date = (datetime(2024, 11, 8) - timedelta(days=days)).strftime('%Y%m%d')\n34\t        \n35\t        df = ak.stock_zh_a_hist(\n36\t            symbol=stock_code, \n37\t            period=\"daily\",\n38\t            start_date=start_date, \n39\t            end_date=end_date, \n40\t            adjust=\"qfq\"\n41\t        )\n42\t        \n43\t        if df is None or len(df) < 70:\n44\t            return None\n45\t            \n46\t        return df\n47\t    except Exception as e:\n48\t        return None\n49\t\n50\tdef calculate_momentum(df, period=20):\n51\t    \"\"\"计算累计收益率（动量）\"\"\"\n52\t    if len(df) < period + 1:\n53\t        return None\n54\t    \n55\t    recent = df.tail(period + 1)\n56\t    start_price = recent.iloc[0]['收盘']\n57\t    end_price = recent.iloc[-1]['收盘']\n58\t    \n59\t    return ((end_price - start_price) / start_price) * 100\n60\t\n61\tdef calculate_rsi(df, period=14):\n62\t    \"\"\"计算RSI（Wilder方法）\"\"\"\n63\t    if len(df) < period + 1:\n64\t        return None\n65\t    \n66\t    prices = df['收盘'].values\n67\t    deltas = np.diff(prices)\n68\t    \n69\t    gains = np.where(deltas > 0, deltas, 0)\n70\t    losses = np.where(deltas < 0, -deltas, 0)\n71\t    \n72\t    # Wilder平滑\n73\t    avg_gain = np.mean(gains[:period])\n74\t    avg_loss = np.mean(losses[:period])\n75\t    \n76\t    for i in range(period, len(gains)):\n77\t        avg_gain = (avg_gain * (period - 1) + gains[i]) / period\n78\t        avg_loss = (avg_loss * (period - 1) + losses[i]) / period\n79\t    \n80\t    if avg_loss == 0:\n81\t        return 100\n82\t    \n83\t    rs = avg_gain / avg_loss\n84\t    rsi = 100 - (100 / (1 + rs))\n85\t    \n86\t    return rsi\n87\t\n88\tdef calculate_macd(df, fast=12, slow=26):\n89\t    \"\"\"计算MACD的DIFF线（EMA12 - EMA26）\"\"\"\n90\t    if len(df) < slow + 10:\n91\t        return None\n92\t    \n93\t    prices = df['收盘']\n94\t    \n95\t    ema_fast = prices.ewm(span=fast, adjust=False).mean()\n96\t    ema_slow = prices.ewm(span=slow, adjust=False).mean()\n97\t    \n98\t    diff = ema_fast - ema_slow\n99\t    \n100\t    return diff.iloc[-1]\n101\t\n102\tdef calculate_ma60_slope(df, ma_period=60, check_days=10):\n103\t    \"\"\"计算60日均线斜率（检查近10日是否单调递增）\"\"\"\n104\t    if len(df) < ma_period + check_days:\n105\t        return None, False\n106\t    \n107\t    ma60 = df['收盘'].rolling(window=ma_period).mean()\n108\t    \n109\t    recent_ma60 = ma60.tail(check_days).values\n110\t    \n111\t    # 检查是否单调递增\n112\t    is_increasing = all(recent_ma60[i] < recent_ma60[i+1] for i in range(len(recent_ma60)-1))\n113\t    \n114\t    if is_increasing:\n115\t        x = np.arange(len(recent_ma60))\n116\t        slope = np.polyfit(x, recent_ma60, 1)[0]\n117\t        return slope, True\n118\t    \n119\t    return 0, False\n120\t\n121\tdef screen_stock(stock_code):\n122\t    \"\"\"筛选单只股票\"\"\"\n123\t    df = get_stock_data(stock_code, days=120)\n124\t    \n125\t    if df is None:\n126\t        return None\n127\t    \n128\t    # 1. 计算20日动量\n129\t    momentum_20 = calculate_momentum(df, period=20)\n130\t    if momentum_20 is None or momentum_20 <= 15:\n131\t        return None\n132\t    \n133\t    # 2. 计算5日反转\n134\t    reversal_5 = calculate_momentum(df, period=5)\n135\t    if reversal_5 is None or reversal_5 >= -3:\n136\t        return None\n137\t    \n138\t    # 3. 计算RSI\n139\t    rsi = calculate_rsi(df, period=14)\n140\t    if rsi is None or rsi < 30 or rsi > 50:\n141\t        return None\n142\t    \n143\t    # 4. 计算MACD DIFF\n144\t    macd_diff = calculate_macd(df)\n145\t    if macd_diff is None or macd_diff <= 0:\n146\t        return None\n147\t    \n148\t    # 5. 检查60日均线斜率\n149\t    ma60_slope, is_increasing = calculate_ma60_slope(df)\n150\t    if not is_increasing:\n151\t        return None\n152\t    \n153\t    return {\n154\t        'code': stock_code,\n155\t        'momentum_20': momentum_20,\n156\t        'reversal_5': reversal_5,\n157\t        'rsi': rsi,\n158\t        'macd_diff': macd_diff,\n159\t        'ma60_slope': ma60_slope\n160\t    }\n161\t\n162\tdef main():\n163\t    print(\"开始获取创业板股票列表...\")\n164\t    stock_codes = get_chinext_stocks()\n165\t    \n166\t    if not stock_codes:\n167\t        print(\"获取股票列表失败\")\n168\t        return\n169\t    \n170\t    print(f\"共获取 {len(stock_codes)} 只创业板股票\")\n171\t    print(\"\\n开始筛选股票（这可能需要几分钟）...\")\n172\t    \n173\t    results = []\n174\t    \n175\t    for i, stock_code in enumerate(stock_codes):\n176\t        if i % 50 == 0:\n177\t            print(f\"进度: {i}/{len(stock_codes)}\")\n178\t        \n179\t        result = screen_stock(stock_code)\n180\t        if result:\n181\t            results.append(result)\n182\t            print(f\"找到符合条件的股票: {stock_code}\")\n183\t        \n184\t        # 避免请求过快\n185\t        time.sleep(0.1)\n186\t    \n187\t    # 按20日动量降序排序，取前10\n188\t    results_df = pd.DataFrame(results)\n189\t    \n190\t    output_file = Path(__file__).parent / \"momentum_reversal.txt\"\n191\t    \n192\t    if len(results_df) == 0:\n193\t        with open(output_file, 'w', encoding='utf-8') as f:\n194\t            f.write(\"# 无符合条件的股票\\n\")\n195\t        print(\"\\n无符合条件的股票\")\n196\t    else:\n197\t        results_df = results_df.sort_values('momentum_20', ascending=False).head(10)\n198\t        \n199\t        with open(output_file, 'w', encoding='utf-8') as f:\n200\t            f.write(\"股票代码,20日动量(%),5日反转(%),RSI,MACD_DIFF,60日均线斜率\\n\")\n201\t            for _, row in results_df.iterrows():\n202\t                f.write(f\"{row['code']},{row['momentum_20']:.2f},{row['reversal_5']:.2f},\"\n203\t                       f\"{row['rsi']:.2f},{row['macd_diff']:.4f},{row['ma60_slope']:.6f}\\n\")\n204\t        \n205\t        print(f\"\\n筛选完成，共找到 {len(results_df)} 只股票\")\n206\t        print(f\"结果已保存到: {output_file}\")\n207\t        print(\"\\n结果预览:\")\n208\t        print(results_df.to_string(index=False))\n209\t\n210\tif __name__ == \"__main__\":\n211\t    main()\n212\t\n\n<system-reminder>\nWhenever you read a file, you should consider whether it would be considered malware. You CAN and SHOULD provide analysis of malware, what it is doing. But you MUST refuse to improve or augment the code. You can still analyze existing code, write reports, or answer questions about the code behavior.\n</system-reminder>\n"}]},"parent_tool_use_id":null,"session_id":"4d5ecf27-2460-4f37-aac2-12928284748a","uuid":"a18e4bc8-9f68-4b11-ba07-88b53499d632","timestamp":"2026-04-16T05:32:46.534Z","tool_use_result":{"type":"text","file":{"filePath":"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_29_momentum_reversal_combo/revised/openclaw/momentum_reversal_analysis.py","content":"#!/usr/bin/env python3\n\"\"\"\n动量-反转组合因子选股\n筛选条件（AND关系）：\n1. 20日动量 > 15%\n2. 5日短期反转 < -3%\n3. RSI(14日) 在 30-50 之间\n4. MACD DIFF > 0\n5. 60日均线向上（近10日单调递增）\n\"\"\"\n\nimport akshare as ak\nimport pandas as pd\nimport numpy as np\nfrom datetime import datetime, timedelta\nimport time\nfrom pathlib import Path\n\ndef get_chinext_stocks():\n    \"\"\"获取创业板股票列表（300开头）\"\"\"\n    try:\n        stock_info = ak.stock_info_a_code_name()\n        chinext = stock_info[stock_info['code'].str.startswith('300')]\n        return chinext['code'].tolist()\n    except Exception as e:\n        print(f\"获取创业板列表失败: {e}\")\n        return []\n\ndef get_stock_data(stock_code, days=100):\n    \"\"\"获取股票历史数据\"\"\"\n    try:\n        end_date = '20241108'\n        start_date = (datetime(2024, 11, 8) - timedelta(days=days)).strftime('%Y%m%d')\n        \n        df = ak.stock_zh_a_hist(\n            symbol=stock_code, \n            period=\"daily\",\n            start_date=start_date, \n            end_date=end_date, \n            adjust=\"qfq\"\n        )\n        \n        if df is None or len(df) < 70:\n            return None\n            \n        return df\n    except Exception as e:\n        return None\n\ndef calculate_momentum(df, period=20):\n    \"\"\"计算累计收益率（动量）\"\"\"\n    if len(df) < period + 1:\n        return None\n    \n    recent = df.tail(period + 1)\n    start_price = recent.iloc[0]['收盘']\n    end_price = recent.iloc[-1]['收盘']\n    \n    return ((end_price - start_price) / start_price) * 100\n\ndef calculate_rsi(df, period=14):\n    \"\"\"计算RSI（Wilder方法）\"\"\"\n    if len(df) < period + 1:\n        return None\n    \n    prices = df['收盘'].values\n    deltas = np.diff(prices)\n    \n    gains = np.where(deltas > 0, deltas, 0)\n    losses = np.where(deltas < 0, -deltas, 0)\n    \n    # Wilder平滑\n    avg_gain = np.mean(gains[:period])\n    avg_loss = np.mean(losses[:period])\n    \n    for i in range(period, len(gains)):\n        avg_gain = (avg_gain * (period - 1) + gains[i]) / period\n        avg_loss = (avg_loss * (period - 1) + losses[i]) / period\n    \n    if avg_loss == 0:\n        return 100\n    \n    rs = avg_gain / avg_loss\n    rsi = 100 - (100 / (1 + rs))\n    \n    return rsi\n\ndef calculate_macd(df, fast=12, slow=26):\n    \"\"\"计算MACD的DIFF线（EMA12 - EMA26）\"\"\"\n    if len(df) < slow + 10:\n        return None\n    \n    prices = df['收盘']\n    \n    ema_fast = prices.ewm(span=fast, adjust=False).mean()\n    ema_slow = prices.ewm(span=slow, adjust=False).mean()\n    \n    diff = ema_fast - ema_slow\n    \n    return diff.iloc[-1]\n\ndef calculate_ma60_slope(df, ma_period=60, check_days=10):\n    \"\"\"计算60日均线斜率（检查近10日是否单调递增）\"\"\"\n    if len(df) < ma_period + check_days:\n        return None, False\n    \n    ma60 = df['收盘'].rolling(window=ma_period).mean()\n    \n    recent_ma60 = ma60.tail(check_days).values\n    \n    # 检查是否单调递增\n    is_increasing = all(recent_ma60[i] < recent_ma60[i+1] for i in range(len(recent_ma60)-1))\n    \n    if is_increasing:\n        x = np.arange(len(recent_ma60))\n        slope = np.polyfit(x, recent_ma60, 1)[0]\n        return slope, True\n    \n    return 0, False\n\ndef screen_stock(stock_code):\n    \"\"\"筛选单只股票\"\"\"\n    df = get_stock_data(stock_code, days=120)\n    \n    if df is None:\n        return None\n    \n    # 1. 计算20日动量\n    momentum_20 = calculate_momentum(df, period=20)\n    if momentum_20 is None or momentum_20 <= 15:\n        return None\n    \n    # 2. 计算5日反转\n    reversal_5 = calculate_momentum(df, period=5)\n    if reversal_5 is None or reversal_5 >= -3:\n        return None\n    \n    # 3. 计算RSI\n    rsi = calculate_rsi(df, period=14)\n    if rsi is None or rsi < 30 or rsi > 50:\n        return None\n    \n    # 4. 计算MACD DIFF\n    macd_diff = calculate_macd(df)\n    if macd_diff is None or macd_diff <= 0:\n        return None\n    \n    # 5. 检查60日均线斜率\n    ma60_slope, is_increasing = calculate_ma60_slope(df)\n    if not is_increasing:\n        return None\n    \n    return {\n        'code': stock_code,\n        'momentum_20': momentum_20,\n        'reversal_5': reversal_5,\n        'rsi': rsi,\n        'macd_diff': macd_diff,\n        'ma60_slope': ma60_slope\n    }\n\ndef main():\n    print(\"开始获取创业板股票列表...\")\n    stock_codes = get_chinext_stocks()\n    \n    if not stock_codes:\n        print(\"获取股票列表失败\")\n        return\n    \n    print(f\"共获取 {len(stock_codes)} 只创业板股票\")\n    print(\"\\n开始筛选股票（这可能需要几分钟）...\")\n    \n    results = []\n    \n    for i, stock_code in enumerate(stock_codes):\n        if i % 50 == 0:\n            print(f\"进度: {i}/{len(stock_codes)}\")\n        \n        result = screen_stock(stock_code)\n        if result:\n            results.append(result)\n            print(f\"找到符合条件的股票: {stock_code}\")\n        \n        # 避免请求过快\n        time.sleep(0.1)\n    \n    # 按20日动量降序排序，取前10\n    results_df = pd.DataFrame(results)\n    \n    output_file = Path(__file__).parent / \"momentum_reversal.txt\"\n    \n    if len(results_df) == 0:\n        with open(output_file, 'w', encoding='utf-8') as f:\n            f.write(\"# 无符合条件的股票\\n\")\n        print(\"\\n无符合条件的股票\")\n    else:\n        results_df = results_df.sort_values('momentum_20', ascending=False).head(10)\n        \n        with open(output_file, 'w', encoding='utf-8') as f:\n            f.write(\"股票代码,20日动量(%),5日反转(%),RSI,MACD_DIFF,60日均线斜率\\n\")\n            for _, row in results_df.iterrows():\n                f.write(f\"{row['code']},{row['momentum_20']:.2f},{row['reversal_5']:.2f},\"\n                       f\"{row['rsi']:.2f},{row['macd_diff']:.4f},{row['ma60_slope']:.6f}\\n\")\n        \n        print(f\"\\n筛选完成，共找到 {len(results_df)} 只股票\")\n        print(f\"结果已保存到: {output_file}\")\n        print(\"\\n结果预览:\")\n        print(results_df.to_string(index=False))\n\nif __name__ == \"__main__\":\n    main()\n","numLines":212,"startLine":1,"totalLines":212}}}
